rule.query:
{
  "z_flag_unset": {
    "Z": 0
  },
  "most_probable_valid_domain": {
    "query|contains": "."
  },
  "exclude_tlds": {
    "query|endswith": [
      ".arpa",
      ".local",
      ".ultradns.net",
      ".twtrdns.net",
      ".azuredns-prd.info",
      ".azure-dns.com",
      ".azuredns-ff.info",
      ".azuredns-ff.org",
      ".azuregov-dns.org"
    ]
  },
  "exclude_query_types": {
    "qtype_name": [
      "ns",
      "mx"
    ]
  },
  "exclude_responses": {
    "answers|endswith": "\\\\x00"
  },
  "exclude_netbios": {
    "id.resp_p": [
      137,
      138,
      139
    ]
  },
  "condition": "not z_flag_unset and most_probable_valid_domain and not (exclude_tlds or exclude_query_types or exclude_responses or exclude_netbios)"
}
